import React, { useState, useEffect } from 'react';
import axios from 'axios';  // Add this import at the top
import { fetchFigmaData } from '../figmaapi.js';  // Import the function from figmaapi.js
import './button.css';  // Import the CSS file for styling

const Button = () => {
    const handleFetch = async () => {
        try {
            const data = await fetchFigmaData();
            console.log('Fetched Figma data:', data);
        } catch (error) {
            console.error('Error fetching data:', error);
        }
    };

    return <button onClick={handleFetch}>Fetch Figma Data</button>;
};

export default Button;
